@import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700;800;900&display=swap');
@import "tailwindcss";

@theme {
  --color-primary: #487ba4;
  --color-primary-light: #60A5FA;
  --color-primary-dark: #3d698c;
  --color-primary-50: #EFF6FF;
  --color-primary-100: #DBEAFE;

  --color-surface: #F8FAFC;
  --color-surface-card: #FFFFFF;
  --color-surface-elevated: #F1F5F9;
  --color-surface-border: #E2E8F0;
  --color-surface-sidebar: #0F172A;

  --color-text-heading: #0F172A;
  --color-text-body: #334155;
  --color-text-secondary: #64748B;
  --color-text-muted: #94A3B8;
  --color-text-inverse: #FFFFFF;

  --color-success: #10B981;
  --color-success-light: #D1FAE5;
  --color-warning: #F59E0B;
  --color-warning-light: #FEF3C7;
  --color-danger: #EF4444;
  --color-danger-light: #FEE2E2;

  --font-sans: 'Inter', system-ui, -apple-system, sans-serif;

  --shadow-soft: 0 1px 3px rgba(0,0,0,0.04), 0 1px 2px rgba(0,0,0,0.03);
  --shadow-card: 0 4px 6px -1px rgba(0,0,0,0.05), 0 2px 4px -2px rgba(0,0,0,0.05);
  --shadow-elevated: 0 10px 25px -5px rgba(0,0,0,0.08), 0 4px 10px -4px rgba(0,0,0,0.04);
  --shadow-hover: 0 20px 40px -10px rgba(72,123,164,0.18), 0 8px 16px -6px rgba(0,0,0,0.06);
}

html.dark {
  --color-primary: #38bdf8;
  --color-primary-light: #7dd3fc;
  --color-primary-dark: #0284c7;
  --color-primary-50: #0c4a6e;
  --color-primary-100: #075985;

  --color-surface: #0b0f19;
  --color-surface-card: #151f32;
  --color-surface-elevated: #1e293b;
  --color-surface-border: #1e293b;
  --color-surface-sidebar: #060913;

  --color-text-heading: #f8fafc;
  --color-text-body: #cbd5e1;
  --color-text-secondary: #94a3b8;
  --color-text-muted: #64748b;

  --shadow-soft: 0 1px 3px rgba(0,0,0,0.3);
  --shadow-card: 0 4px 6px -1px rgba(0,0,0,0.4), 0 2px 4px -2px rgba(0,0,0,0.4);
  --shadow-elevated: 0 10px 25px -5px rgba(0,0,0,0.5);
  --shadow-hover: 0 20px 40px -10px rgba(56,189,248,0.2), 0 8px 16px -6px rgba(0,0,0,0.4);
}

html.emerald {
  --color-primary: #10B981;
  --color-primary-light: #34D399;
  --color-primary-dark: #047857;
  --color-primary-50: #ECFDF5;
  --color-primary-100: #D1FAE5;

  --color-surface: #F4FBF7;
  --color-surface-card: #FFFFFF;
  --color-surface-elevated: #E6F4EA;
  --color-surface-border: #D1E7DD;
  --color-surface-sidebar: #062F21;

  --color-text-heading: #062F21;
  --color-text-body: #1E3A2F;
  --color-text-secondary: #3B6053;
  --color-text-muted: #739C8C;

  --shadow-hover: 0 20px 40px -10px rgba(16,185,129,0.2), 0 8px 16px -6px rgba(0,0,0,0.06);
}

@layer base {
  * { margin: 0; padding: 0; box-sizing: border-box; }
  html { scroll-behavior: smooth; -webkit-font-smoothing: antialiased; -moz-osx-font-smoothing: grayscale; }
  body { font-family: var(--font-sans); background-color: var(--color-surface); color: var(--color-text-body); }
  h1,h2,h3,h4,h5,h6 { color: var(--color-text-heading); font-weight: 600; }
}

/* ── Core Animations ── */
@keyframes fadeIn {
  from { opacity: 0; transform: translateY(10px); }
  to   { opacity: 1; transform: translateY(0); }
}
@keyframes fadeInFast {
  from { opacity: 0; transform: translateY(6px); }
  to   { opacity: 1; transform: translateY(0); }
}
@keyframes slideIn {
  from { opacity: 0; transform: translateX(-14px); }
  to   { opacity: 1; transform: translateX(0); }
}
@keyframes slideInRight {
  from { opacity: 0; transform: translateX(14px); }
  to   { opacity: 1; transform: translateX(0); }
}
@keyframes scaleIn {
  from { opacity: 0; transform: scale(0.95); }
  to   { opacity: 1; transform: scale(1); }
}
@keyframes pulse-gently {
  0%, 100% { transform: scale(1); opacity: 1; }
  50%       { transform: scale(1.03); opacity: 0.95; }
}
@keyframes pulse-dot {
  0%, 100% { transform: scale(1); opacity: 1; }
  50%       { transform: scale(1.4); opacity: 0.7; }
}
@keyframes shimmer {
  0%   { background-position: -200% 0; }
  100% { background-position:  200% 0; }
}

/* 3D Float animations (login page) */
@keyframes float3d-a {
  0%, 100% { transform: translateY(0px) rotateX(0deg) rotateZ(0deg); }
  33%       { transform: translateY(-10px) rotateX(3deg) rotateZ(1deg); }
  66%       { transform: translateY(-5px) rotateX(-2deg) rotateZ(-1deg); }
}
@keyframes float3d-b {
  0%, 100% { transform: translateY(0px) rotateX(0deg) rotateZ(0deg); }
  33%       { transform: translateY(-8px) rotateX(-3deg) rotateZ(-1deg); }
  66%       { transform: translateY(-14px) rotateX(2deg) rotateZ(1.5deg); }
}
@keyframes float3d-c {
  0%, 100% { transform: translateY(0px) rotateX(0deg); }
  50%       { transform: translateY(-12px) rotateX(4deg); }
}

/* Orbit ring animations */
@keyframes spinRing {
  from { transform: rotateZ(0deg) rotateX(70deg); }
  to   { transform: rotateZ(360deg) rotateX(70deg); }
}
@keyframes spinRing2 {
  from { transform: rotateZ(60deg) rotateX(70deg); }
  to   { transform: rotateZ(420deg) rotateX(70deg); }
}
@keyframes spinRingVert {
  from { transform: rotateY(0deg) rotateX(10deg); }
  to   { transform: rotateY(360deg) rotateX(10deg); }
}

/* Sidebar glow pulse */
@keyframes sidebarGlow {
  0%, 100% { opacity: 0.15; }
  50%       { opacity: 0.3; }
}

/* Progress bar fill */
@keyframes progressFill {
  from { width: 0%; }
  to   { width: var(--progress-width, 100%); }
}

/* Gradient sweep */
@keyframes gradientSweep {
  0%   { background-position: 0% 50%; }
  50%  { background-position: 100% 50%; }
  100% { background-position: 0% 50%; }
}

/* Stagger children */
@keyframes staggerFade {
  from { opacity: 0; transform: translateY(12px); }
  to   { opacity: 1; transform: translateY(0); }
}

/* ── Utility Classes ── */
@utility animate-fade-in       { animation: fadeIn 0.4s cubic-bezier(0.16, 1, 0.3, 1) forwards; }
@utility animate-fade-in-fast  { animation: fadeInFast 0.25s cubic-bezier(0.16, 1, 0.3, 1) forwards; }
@utility animate-slide-in      { animation: slideIn 0.35s cubic-bezier(0.16, 1, 0.3, 1) forwards; }
@utility animate-slide-in-right{ animation: slideInRight 0.35s cubic-bezier(0.16, 1, 0.3, 1) forwards; }
@utility animate-scale-in      { animation: scaleIn 0.3s cubic-bezier(0.16, 1, 0.3, 1) forwards; }
@utility animate-pulse-gentle  { animation: pulse-gently 3s ease-in-out infinite; }
@utility animate-float-a       { animation: float3d-a 5s ease-in-out infinite; }
@utility animate-float-b       { animation: float3d-b 6s ease-in-out infinite 0.8s; }
@utility animate-float-c       { animation: float3d-c 4.5s ease-in-out infinite 1.5s; }

/* Stagger delays */
@utility stagger-1  { animation-delay: 0.05s; }
@utility stagger-2  { animation-delay: 0.1s; }
@utility stagger-3  { animation-delay: 0.15s; }
@utility stagger-4  { animation-delay: 0.2s; }
@utility stagger-5  { animation-delay: 0.25s; }

/* ── Glass Card ── */
@utility glass-card {
  background-color: rgba(255, 255, 255, 0.75);
  backdrop-filter: blur(14px);
  -webkit-backdrop-filter: blur(14px);
  border: 1px solid rgba(226, 232, 240, 0.5);
}
.dark .glass-card {
  background-color: rgba(21, 31, 50, 0.65);
  border: 1px solid rgba(255, 255, 255, 0.06);
}

/* ── Primary Glow Shadow ── */
@utility shadow-primary-glow {
  box-shadow: 0 4px 20px -2px rgba(72, 123, 164, 0.25), 0 2px 8px -2px rgba(72, 123, 164, 0.1);
}
.dark .shadow-primary-glow    { box-shadow: 0 4px 20px -2px rgba(56, 189, 248, 0.3); }
.emerald .shadow-primary-glow { box-shadow: 0 4px 20px -2px rgba(16, 185, 129, 0.25); }

/* ── Hover Lift ── */
.hover-lift {
  transition: transform 0.28s cubic-bezier(0.34, 1.56, 0.64, 1),
              box-shadow 0.28s cubic-bezier(0.34, 1.56, 0.64, 1);
}
.hover-lift:hover {
  transform: translateY(-4px);
  box-shadow: var(--shadow-hover);
}

/* ── Stat Card 3D Tilt ── */
.stat-card-3d {
  transition: transform 0.25s cubic-bezier(0.4, 0, 0.2, 1),
              box-shadow 0.25s ease;
  transform-style: preserve-3d;
  will-change: transform;
}
.stat-card-3d:hover {
  transform: perspective(600px) rotateX(-4deg) rotateY(4deg) translateY(-5px);
  box-shadow: 0 22px 44px -12px rgba(72, 123, 164, 0.22),
              0 8px 16px -6px rgba(0, 0, 0, 0.08);
}
.dark .stat-card-3d:hover {
  box-shadow: 0 22px 44px -12px rgba(56, 189, 248, 0.2),
              0 8px 16px -6px rgba(0, 0, 0, 0.4);
}

/* ── Sidebar Navigation ── */
.sidebar-link {
  transition: all 0.22s cubic-bezier(0.4, 0, 0.2, 1);
  position: relative;
}
.sidebar-link.active::before {
  content: '';
  position: absolute;
  left: 0;
  top: 50%;
  transform: translateY(-50%);
  width: 3px;
  height: 60%;
  border-radius: 0 3px 3px 0;
  background: var(--color-primary);
}
.sidebar-link:not(.active):hover {
  padding-left: 1.5rem !important;
  color: #ffffff !important;
  background-color: rgba(255, 255, 255, 0.07);
}

/* ── Heatmap Tiles ── */
.heatmap-tile {
  transition: all 0.15s cubic-bezier(0.4, 0, 0.2, 1);
  border-radius: 3px;
}
.heatmap-tile:hover {
  transform: scale(1.3) !important;
  filter: brightness(1.15) drop-shadow(0 0 6px var(--color-primary));
  z-index: 10;
  border-radius: 4px;
}

/* ── Checklist Item ── */
.checklist-item {
  transition: all 0.22s cubic-bezier(0.4, 0, 0.2, 1);
  border-radius: 0.75rem;
}
.checklist-item:hover {
  background-color: var(--color-surface-elevated);
  transform: translateX(4px);
}

/* ── Login Page ── */
.login-3d-scene {
  perspective: 900px;
  perspective-origin: 50% 40%;
}
.input-glow {
  transition: border-color 0.2s ease, box-shadow 0.2s ease, background-color 0.2s ease;
}
.input-glow:focus {
  box-shadow: 0 0 0 4px rgba(72, 123, 164, 0.12);
  border-color: #487ba4;
  outline: none;
  background-color: #fafcff;
}
.dark .input-glow:focus {
  background-color: rgba(255, 255, 255, 0.03);
  box-shadow: 0 0 0 4px rgba(56, 189, 248, 0.12);
  border-color: #38bdf8;
}

/* Profile photo upload */
.photo-upload-ring {
  transition: all 0.3s cubic-bezier(0.34, 1.56, 0.64, 1);
}
.photo-upload-ring:hover {
  box-shadow: 0 0 0 4px rgba(72, 123, 164, 0.25), 0 8px 24px rgba(72, 123, 164, 0.15);
  transform: scale(1.04);
}

/* ── Patient Card (Doctor sidebar) ── */
.patient-card {
  transition: all 0.2s cubic-bezier(0.4, 0, 0.2, 1);
}
.patient-card:hover {
  background: rgba(72, 123, 164, 0.05);
  padding-left: 1.5rem !important;
  border-left-color: var(--color-primary) !important;
}
.dark .patient-card:hover {
  background: rgba(56, 189, 248, 0.06);
}

/* ── Card Section Divider ── */
.section-header {
  display: flex;
  align-items: center;
  gap: 0.75rem;
}
.section-header::after {
  content: '';
  flex: 1;
  height: 1px;
  background: linear-gradient(to right, var(--color-surface-border), transparent);
}

/* ── Scrollbar Styling ── */
::-webkit-scrollbar { width: 6px; height: 6px; }
::-webkit-scrollbar-track { background: transparent; }
::-webkit-scrollbar-thumb {
  background: var(--color-surface-border);
  border-radius: 3px;
  transition: background 0.2s;
}
::-webkit-scrollbar-thumb:hover { background: var(--color-text-muted); }

/* ── Notification badge pulse ── */
.badge-pulse {
  animation: pulse-dot 2s ease-in-out infinite;
}

/* ── Button press effect ── */
.btn-press {
  transition: transform 0.1s ease, box-shadow 0.1s ease;
}
.btn-press:active { transform: scale(0.97); }

/* ── Gradient animated background ── */
.gradient-animated {
  background-size: 200% 200%;
  animation: gradientSweep 6s ease infinite;
}

/* ── Chart container fade ── */
.chart-wrapper {
  animation: fadeIn 0.5s ease-out 0.2s both;
}

/* ── Progress bar ── */
.progress-bar-fill {
  transition: width 0.8s cubic-bezier(0.34, 1.56, 0.64, 1);
}

/* ── Skeleton shimmer ── */
.skeleton {
  background: linear-gradient(90deg,
    var(--color-surface-elevated) 0%,
    var(--color-surface-card) 50%,
    var(--color-surface-elevated) 100%);
  background-size: 200% 100%;
  animation: shimmer 1.5s ease-in-out infinite;
}

